#include<bits/stdc++.h>
using namespace std;
int n,m,s[300010];
struct node
{
    int l,r,id;
    bool operator<(const node&b)const
    {
        return r<b.r;
    }
}b[300010],c[600010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(;x<=n;x+=lowbit(x))
    {
        s[x]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(;x>=1;x-=lowbit(x))
    {
        ans+=s[x];
    }
    return ans;
}
struct num
{
    int x,id;
    bool operator<(const num&b)const
    {
        return x<b.x;
    }
}a[300010];
int tot=0;
void add1(num a,num b)
{
    int l=min(a.id,b.id),r=max(a.id,b.id);
    c[++tot].l=l;
    c[tot].r=r;
    c[tot].id=tot;
}
int main()
{
    scanf("%d%d",&n,&m);
    if(n==1)
    {
        printf("0");
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i].id=i;
    }
    sort(a+1,a+1+n);
    add1(a[1],a[2]);
    add1(a[n-1],a[n]);
    for(int i=2;i<n;i++)
    {
        int l=a[i].x-a[i-1].x,r=a[i+1].x-a[i].x;
        if(l<=r)
        {
            add1(a[i-1],a[i]);
        }
        if(l>=r)
        {
            add1(a[i],a[i+1]);
        }
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&b[i].l,&b[i].r);
        b[i].id=i;
    }
    int j=1;
    sort(b+1,b+1+m);
    sort(c+1,c+1+tot);
    long long ans=0;
    for(int i=1;i<=m;i++)
    {
        for(;c[j].r<=b[i].r&&j<=tot;j++)
        {
            add(c[j].l,1);
        }
        ans+=1ll*b[i].id*(j-1-query(b[i].l-1));
    }
    printf("%lld",ans);
    return 0;
}
